function Tooltip({ targetRef }) {
  const [top, setTop] = useState(0);
  useLayoutEffect(() => {
    const rect = targetRef.current.getBoundingClientRect();
    setTop(rect.bottom + window.scrollY);
  }, [targetRef]);
  return <div style={{ position: "absolute", top }}>Hint</div>;
}

